5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
7	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
8	const COMPONENT_BASE = 25;
9	const BLOCK_SIZE = 3;
10	const BLOCK_BASE = 60;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: COMPONENT_BASE,
18	  moonstone: COMPONENT_BASE,
19	};
