21	const groupBaseTotal = (items: Item[]): number => {
22	  const counts = new Map<string, number>();
23	  let total = 0;
24	  for (const item of items) {
25	    if (COMPONENT_TYPES.has(item.type)) {
26	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
27	    } else {
28	      total += BASE_PREMIUMS[item.type];
29	    }
30	  }
31	  for (const count of counts.values()) {
32	    const blocks = Math.floor(count / BLOCK_SIZE);
33	    const remainder = count % BLOCK_SIZE;
34	    total += blocks * BLOCK_BASE + remainder * COMPONENT_BASE;
35	  }
36	  return total;
37	};
38	
39	const quoteItems = (items: Item[]): number => {
40	  const base = groupBaseTotal(items);
41	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
42	  return Math.ceil(base + firstInsuranceSurcharge + PROCESSING_FEE);
43	};
44	
45	export const runScenario = (input: Scenario): { results: { premium: number }[] } => {
46	  const results = input.steps.map((step) => ({ premium: quoteItems(step.items) }));
47	  return { results };
48	};
